class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {}
        self.next = {}
        self.prev = {}
        self.head = 0
        self.tail = 0

    def _remove(self, key: int):
        if key not in self.cache:
            return
        nxt = self.next[key]
        prv = self.prev[key]
        if nxt == key:
            self.head = 0
            self.tail = 0
        else:
            self.next[prv] = nxt
            self.prev[nxt] = prv
            if self.head == key:
                self.head = nxt
            if self.tail == key:
                self.tail = prv
        del self.next[key]
        del self.prev[key]

    def _add_recent(self, key: int):
        if self.head == 0:
            self.head = key
            self.tail = key
            self.next[key] = key
            self.prev[key] = key
        else:
            old_head = self.head
            self.next[key] = old_head
            self.prev[key] = self.tail
            self.next[self.tail] = key
            self.prev[old_head] = key
            self.head = key

    def get(self, key: int):
        if key not in self.cache:
            return None
        self._remove(key)
        self._add_recent(key)
        return self.cache[key]

    def put(self, key: int, value: int):
        if key in self.cache:
            self._remove(key)
        elif len(self.cache) == self.capacity:
            lru = self.tail
            self._remove(lru)
            del self.cache[lru]
        self.cache[key] = value
        self._add_recent(key)
